async function checkAccess(){const e=document.getElementById("admin-pass").value,t=document.getElementById("login-error");try{if(await hashString(e)==="4de9a48824f9ca72125798e7eca051baf13c3e3a403d7fdcf0662f4844fd28ea"){document.getElementById("login-section").style.display="none",document.getElementById("stats-content").style.display="block",loadStats()}else t.style.display="block",t.innerText="Incorrect Password"}catch(n){t.style.display="block",t.innerText="Security error."}}async function hashString(e){const t=(new TextEncoder).encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map(e=>e.toString(16).padStart(2,"0")).join("")}async function loadStats(){const e=document.getElementById("visit-count");e.innerText="Loading...";try{const t=Date.now(),n=`https://api.counterapi.dev/v1/josemanuel31675-cv/visits?t=${t}`,s=await fetch(`https://api.allorigins.win/get?url=${encodeURIComponent(n)}`);if(!s.ok)throw new Error("Proxy unreachable");const a=await s.json(),r=JSON.parse(a.contents);if(r&&r.count!==undefined)e.innerText=r.count;else throw new Error("Data structure invalid")}catch(t){e.innerHTML='<div style="font-size:1rem;color:#666"><p style="color:#e74c3c">Blocked by Browser (CORS)</p><a href="https://api.counterapi.dev/v1/josemanuel31675-cv/visits" target="_blank" style="display:inline-block;margin-top:10px;color:var(--primary);text-decoration:underline">Click to view real-time count</a></div>'}}
